sql:
SELECT COUNT(*) AS unique_users
FROM (
    SELECT DISTINCT user_id FROM users
    UNION
    SELECT DISTINCT user_id FROM configuration_logs
) AS combined_users;

SELECT TRIM(mcu_model), TRIM(serial_number)
FROM microcontrollers
WHERE mcu_id = 0;

external_knowledge:
- "hidden shadows" refers to the anomalies detected in the system;
- "realm of malfunction" refers to the anomalies that have been detected but not yet addressed;
- "once-vibrant microcontrollers" refers to those microcontrollers that were once operational but are now inactive.

sql:
SELECT microcontrollers.mcu_model, maintenance_logs.maintenance_type, maintenance_logs.maintenance_details
FROM microcontrollers
JOIN maintenance_logs ON microcontrollers.mcu_id = maintenance_logs.mcu_id;

SELECT m.mcu_id, m.mcu_model, m.last_check_in, u.username, u.email
FROM microcontrollers m
INNER JOIN users u ON m.owner = u.username;

SELECT bit_number, description, value
FROM adc_configurations
WHERE config_id = 1;
